function LxLoginHandler:AuthReq()
    ---@type LxServerItem
    local serverItem = ModuleCenter.Login:GetLoginServer()

    local responseData = ModuleCenter.Login.httpAuthResponseData

    local proto = LxProtoHelper.CreateProto(LxProtoIds.AuthReq)
    proto.identityId = ModuleCenter.Login:GetLoginIdentityId()
    proto.timeStamp = tostring(responseData.timestamp)
    proto.sign = responseData.sign
    proto.serverId = serverItem.id
    proto.userId = ModuleCenter.Login:GetAccount()
    proto.networkType = 1
    proto.uuid = LxPlayerPrefs.uuid
    proto.deviceType = LxAppHelper.getDeviceType()
    proto.deviceModel = LxAppHelper.getDeviceModel()
    proto.appResVersion = gLxServerList.webPackageVersion
    proto.appVersion = gLxServerList.webAppVersion
    proto.platformId = gLxServerList:GetPlatformId()
    proto.channelId = gLxServerList:GetChannelId()
    proto.deviceVersion = LxAppHelper.getDeviceVersion()
    proto.devicePX = tostring(DESIGN_SCREEN_SIZE.Width).."X"..tostring(DESIGN_SCREEN_SIZE.Height)
    proto.deviceCPU = "0"
    proto.deviceRAM =  "0"
    proto.gpu = LxAppHelper.getGpuInfo()
    proto.language = LxPlayerPrefs.language
    proto.sdkParameters = gLxSdkImpl:CallMethod(SdkMethod.GetSensorProperties, true) or ""
    SendMessage(LxProtoIds.AuthReq, proto)
end

