--- s2c
function LxLoginHandler:OnAuthResp(pb)

    ModuleCenter.Login:SetSessionId(pb.sessionId)
    CtrlCenter.Login:OnAuthResult(pb.result, pb.version)
end

function LxLoginHandler:OnHeartbeatResp(pb)
    local serverTime = tonumber(pb.serverTime)
    local rawOffset = pb.rawOffset
    ModuleCenter.Login:SetServerTime(serverTime, rawOffset)
end

function LxLoginHandler:OnServerTimeResp(pb)
    local serverTime = tonumber(pb.serverTime)
    local rawOffset = pb.rawOffset
    MgrCenter.NetworkMgr:SetServerTime(tostring(pb.serverTime))
    ModuleCenter.Login:SetServerTime(serverTime, rawOffset)
    CtrlCenter.Login:GetServerTimerOk()

end

function LxLoginHandler:OnQuitResp(pb)
    CtrlCenter.Login:DoQuitFromServer(pb.type, pb.sessionId)
end

function LxLoginHandler:OnResVersionResp(pb)
    CtrlCenter.Login:CheckResVersionFormServer(pb.resVersion, pb.forceUpdate > 0)
end

function LxLoginHandler:OnDisabledResp(pb)
    CtrlCenter.Login:OnDisableFormServer()
end

function LxLoginHandler:OnGetRoleResp(pb)
    local roles = pb.roles
    if table.isempty(roles) or table.isempty(roles[1]) then
        CtrlCenter.Login:ToCreateRole()
        return
    end
    local latestLoginRole = tostring(pb.latestLoginRole)

    local simpleInfos = {}
    local curInfo = nil
    for i, v in ipairs(roles) do
        local info = ModuleCenter.Common:NewRoleSimpleInfo(v)
        table.insert(simpleInfos, info)
        --- 上次选择的角色
        if latestLoginRole == info.roleId  then
            curInfo = info
        end
    end

    ModuleCenter.Login:SetLoginRoleList(simpleInfos)
    ModuleCenter.Login:SetLatestLoginRoleId(latestLoginRole)

    if not curInfo then
        --- 默认选择第一个
        curInfo = roles[1]
    end
    ModuleCenter.Login:SetLoginRole(curInfo)
    ModuleCenter.Login:SetRoleId(curInfo.roleId)
    ModuleCenter.Login:SetRoleName(curInfo.name)
    ModuleCenter.Login:SetRoleLevel(curInfo.level)
    CtrlCenter.Login:OnRoleOk()
end

function LxLoginHandler:OnCreateRoleResp(pb)
    local roleInfo = pb.role
    local simpleInfos = {}
    local curInfo = ModuleCenter.Common:NewRoleSimpleInfo(roleInfo)
    table.insert(simpleInfos, curInfo)

    ModuleCenter.Login:SetLoginRoleList(simpleInfos)
    ModuleCenter.Login:SetLatestLoginRoleId(curInfo.roleId)
    ModuleCenter.Login:SetLoginRole(curInfo)
    ModuleCenter.Login:SetRoleId(curInfo.roleId)
    ModuleCenter.Login:SetRoleName(curInfo.name)
    ModuleCenter.Login:SetRoleLevel(curInfo.level)
    CtrlCenter.Login:OnRoleOk(true)
end

function LxLoginHandler:OnLoginResp(pb)

    CtrlCenter.Login:OnLoginOk()
end

function LxLoginHandler:OnLoginSuccessResp(pb)
    --- 其他数据服务端主动推送
    --- 收到所有后端数据后，进入游戏
    CtrlCenter.Login:EnterGame()
end

return LxLoginHandler